let sale_date = null;
let paid_total = 0;
let unpaid_total = 0;
let ordersMap = {};

// เมื่อวานตามเวลาไทย (Asia/Bangkok) แบบนิ่ง ไม่พึ่ง timezone ของเครื่อง
const nowBkk = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Bangkok' }));
nowBkk.setDate(nowBkk.getDate() - 1);
const yesterdayText = nowBkk.toLocaleDateString('th-TH');

const sheet_url = "https://docs.google.com/spreadsheets/d/1tdmtxnrDUllNzewTxA8Xdc6BrIUH0teCFHJEVoU84sw/edit?usp=sharing";
const looker_url = "https://lookerstudio.google.com/reporting/11d93bcd-f176-46e8-949a-371801353d2a";

// items = ข้อมูลจาก node ก่อนหน้าใน n8n (แต่ละ item = 1 row)
for (const item of items) {
  const j = item.json;

  sale_date = sale_date || j.sale_date;
  const amount = Number(j.subtotal || 0);

  if (j.payment_status === 'ชำระเงินแล้ว') paid_total += amount;
  else unpaid_total += amount;

  // ===== เพิ่ม: แปลงวิธีชำระเงิน (COD = เงินสด) =====
  let paymentMethodText = 'ไม่มีข้อมูล';
  if (j.payment_method === 'COD') paymentMethodText = '💵 เงินสด';
  else if (j.payment_method === 'QR') paymentMethodText = '📲 โอนผ่านธนาคาร';

  if (!ordersMap[j.order_id]) {
    ordersMap[j.order_id] = {
      customer_name: j.customer_name,
      payment_status: j.payment_status,
      payment_method: paymentMethodText,     // << เพิ่ม
      total_amount: 0,
      categories: {}
    };
  }

  const catName = j.cat_name || 'ทั่วไป';
  if (!ordersMap[j.order_id].categories[catName]) {
    ordersMap[j.order_id].categories[catName] = [];
  }

  ordersMap[j.order_id].categories[catName].push(`      ◦ ${j.product_name}\n(จำนวน ${j.qty} ชิ้น)`);
  ordersMap[j.order_id].total_amount += amount;
}

// ทำรายละเอียดรายออเดอร์
let detail_lines = [];
for (const order_id in ordersMap) {
  const order = ordersMap[order_id];

  let categorySections = [];
  for (const cat in order.categories) {
    categorySections.push(`   📂 หมวดหมู่: ${cat}\n${order.categories[cat].join('\n')}`);
  }

  detail_lines.push(
`🆔 ออเดอร์: #${order_id}
👤 ลูกค้า: คุณ ${order.customer_name}
${categorySections.join('\n')}
💰 ยอดรวม: ${order.total_amount.toLocaleString(undefined, { minimumFractionDigits: 2 })} บาท
📍 สถานะชำระเงิน: ${order.payment_status === 'ชำระเงินแล้ว' ? '✅ จ่ายแล้ว' : '⏳ รอชำระ'}
💳 วิธีชำระ: ${order.payment_method}`
  );
}

// ===== ส่วนที่คุณขอ: unshift สรุปขึ้นก่อน =====
let all_messages = [];

all_messages.unshift(
`┏━━━━━━━━━━━━━┓
        📊 สรุปยอดขายประจำวัน
┗━━━━━━━━━━━━━┛
📅 วันที่: ${yesterdayText}

💰 ยอดรวมทั้งหมด: ${(paid_total + unpaid_total).toLocaleString(undefined, { minimumFractionDigits: 2 })} บาท
----------------------------------
✅ จ่ายแล้ว: ${paid_total.toLocaleString(undefined, { minimumFractionDigits: 2 })} บาท
❌ ยังไม่จ่าย: ${unpaid_total.toLocaleString(undefined, { minimumFractionDigits: 2 })} บาท

📊 Dashboard วิเคราะห์ยอดขาย :
🔗 ${looker_url}
📁 ตรวจสอบรายการทั้งหมด :
🔗 ${sheet_url}

ภาพรวมวันนี้ประมาณนี้ครับ 😎`
);

// เติมรายละเอียดตามหลัง (ทีละ 5)
for (let i = 0; i < detail_lines.length; i += 5) {
  const chunk = detail_lines.slice(i, i + 5);

  all_messages.push(
`📝 รายละเอียดรายการ (${i + 1}-${Math.min(i + 5, detail_lines.length)})
━━━━━━━━━━━━━━
${chunk.join('\n------------------------------\n')}
━━━━━━━━━━━━━━`
  );
}

// คืนค่าเป็นหลาย items เพื่อให้ Split Out ทำงานต่อ
return all_messages.map(msg => ({ json: { line_text: msg } }));

