let totalQtyAll = 0;

// ===== เดือนที่แล้ว (เวลาไทย) =====
const nowBkk = new Date(
  new Date().toLocaleString('en-US', { timeZone: 'Asia/Bangkok' })
);

const firstDayThisMonth = new Date(
  nowBkk.getFullYear(),
  nowBkk.getMonth(),
  1
);

const firstDayLastMonth = new Date(firstDayThisMonth);
firstDayLastMonth.setMonth(firstDayLastMonth.getMonth() - 1);

const monthText = firstDayLastMonth.toLocaleDateString('th-TH', {
  year: 'numeric',
  month: 'long'
});

// ===== เอาแค่ 5 อันดับแรก =====
const top5 = items.slice(0, 5);

// ===== รวมจำนวนทั้งหมด (เฉพาะ Top 5) =====
for (const item of top5) {
  totalQtyAll += Number(item.json.total_qty_sold || 0);
}

// ===== สร้างข้อความ =====
let detail_lines = top5.map((item, index) => {
  const category =
    item.json.category_name ||
    item.json.cat_name ||
    'ไม่ระบุหมวดหมู่';

  return `${index + 1}. 🏆 ${item.json.product_name}
   📂 หมวดหมู่: ${category}
   📦 ขายได้: ${Number(item.json.total_qty_sold).toLocaleString()} ชิ้น`;
});

let message = `┏━━━━━━━━━━━━━┓
          📊 5 อันดับสินค้าขายดี
┗━━━━━━━━━━━━━┛
📅 เดือน: ${monthText}
━━━━━━━━━━━━━━
${detail_lines.join('\n------------------------------\n')}
━━━━━━━━━━━━━━`;

return [
  {
    json: {
      line_text: message
    }
  }
];

