const targetDates = [
  { day: 3, month: 3 },
  { day: 9, month: 9 },
  { day: 12, month: 12 }
];

// ตรวจสอบว่าตรงกับวันที่กำหนดหรือไม่
const matched = targetDates.some(d => d.day === day && d.month === month);

return [
  {
    json: {
      today: `${day}/${month}`,
      timezone: "Asia/Bangkok",
      isMatched: matched
    }
  }
];

