  now.toLocaleString("en-US", { timeZone: "Asia/Bangkok" })
);

// เลือกใช้วันจริงหรือวันทดสอบ
const day = testMode ? testDate.day : thaiDate.getDate();
const month = testMode ? testDate.month : thaiDate.getMonth() + 1;

// วันที่ที่ต้องการเช็ค
